function ModelArena:OnModelRequest()
    self:InitData()

    self._isPlayerArenaDataDirty = true

    --local arenaKey = 13000000
    local arenaRankKey = 13100000
    local arenaPeakKey = 13200000
    --local isArenaOpen = gModelFunctionOpen:CheckIsOpened(arenaKey)
    local isArenaOpen = true
    local isArenaRankOpen = gModelFunctionOpen:CheckIsOpened(arenaRankKey)
    local isArenaPeakOpen = gModelFunctionOpen:CheckIsOpened(arenaPeakKey)
    if isArenaOpen then
        if isArenaRankOpen then
            self:OnPlayerArenaReq(true)
        end

        if isArenaPeakOpen then
            self:PinnaclePaceStateReq()
        end
    end

    self:ModelFinish()
end

