end

function ModelArena:OnPlayerArenaResp(pb, ret)

    self._isPlayerArenaDataDirty = false

    self._score = pb.score
    self._rank = pb.rank
    self._combatCount = pb.combatCount
    self._seasonCount = pb.seasonCount
    self._rewardIds = pb.rewardIds
    self._grade = pb.grade
    local oldFlushTime = self._flushTime
    self._flushTime = pb.flushTime
    self._likeIds = pb.likeIds
    self._freeCombatCount = pb.freeCombatCount

    self._serverOpenTime = pb.serverOpenTime

    --[[    FireEvent(EventNames.ON_ARENA_BOX_RED_CHANGE)]]
    --    FireEvent(EventNames.ON_ARENA_FREE_TIME_CHANGE)
    self._likeJudge = {}
    for k, v in ipairs(self._likeIds) do
        self._likeJudge[v] = true
    end

    --local canSkip = self:CanSkipArena(false)
    --
    --if not canSkip then
    --    self:SetIsSkipChecked(false)
    --end

    if oldFlushTime and oldFlushTime ~= self._flushTime then
        self._reqTag = false
        self:OnArenaMatchReq()
    end

end

function ModelArena:GetServerOpenTime()
    local time = self._serverOpenTime or 0
    return time / 1000
end

function ModelArena:OnArenaMatchReq(isClick)
    --首次打开时/每次挑战完/每天重置（0点）后第一次打开
    if not isClick and self._reqTag then
        return false
    end

    self._reqTag = true

    local pb = LProtoHelper.CreateProto(LProtoIds.ArenaMatchReq)
    pb.type = isClick and 1 or 0
    SendMessage(pb, LProtoIds.ArenaMatchReq)
    return true
end

function ModelArena:OnArenaMatchResp(pb, ret)
    self._targets = pb.targets
    local type = pb.type
    if type == 1 then
        GF.ShowMessage(ccClientText(10342))
    end

    self:SetChallengeDataDirty(false)
end

function ModelArena:OnArenaAccount()
    self._isPlayerArenaDataDirty = true
    self._reqTag = false --挑战完重置
    self:OnPlayerArenaReq()
    self:OnArenaMatchReq()


end
