function ModelArena:OnReceiveArenaRewardResp(pb, ret)

    if not self._rewardIds then
        self._rewardIds = {}
    end
    table.insert(self._rewardIds, pb.rewardId)
    --FireEvent(EventNames.ON_ARENA_BOX_RED_CHANGE)
    local itemList = {}
    local datas = pb.rewards
    for i = 1, #datas do
        local data = datas[i]
        itemList[i] = {
            itype = data.type,
            itemId = data.itemId,
            count = data.count
        }
    end
    --local delay = pb.delay
    --local sceneId = pb.sceneId
    gModelWndPop:TryOpenPopWnd("UIAward", { itemList = itemList })
end

