function ModelArena:GetBoxConfig()
    --宝箱配置
    local t = {}
    local grade = self:GetCurGrade()
    for k, v in pairs(GameTable.RookieArenaSeasonBoxRef) do
        local cfg = self:GetSeasonBoxRefT(v.refId)
        if cfg.lvT.left <= grade and cfg.lvT.right >= grade then
            table.insert(t, v)
        end
    end
    table.sort(t, function(a, b)
        return a.refId < b.refId
    end)
    return t
end

