--配置预处理

function ModelArena:ParseConfig()
    self._stageStrList = {
        ccClientText(11800), --海选
        ccClientText(11801), --64
        ccClientText(11801), --32
        ccClientText(11802), --16
        ccClientText(11803), --8
        ccClientText(11804), --半决赛
        ccClientText(11805), --决赛
    }

    self._rankAwardRefT = {}
    for k, v in pairs(GameTable.RookieArenaRankAwardRef) do
        local t = {}
        local rank = v.rank
        t.rankT = self:ParseRange(rank)
        local dailyReward = v.dailyReward
        t.dailyRewardT = LxDataHelper.ParseItem(dailyReward)
        local seasonReward = v.seasonReward
        local titleReward = v.titleReward
        local tRewardList = LxDataHelper.ParseItem(titleReward) or {}
        local seasonRewardT = LxDataHelper.ParseItem(seasonReward)
        for p, q in ipairs(seasonRewardT) do
            table.insert(tRewardList, q)
        end
        t.seasonRewardT = tRewardList
        self._rankAwardRefT[k] = t
    end

    self._seasonBoxRefT = {}
    for k, v in pairs(GameTable.RookieArenaSeasonBoxRef) do
        local t = {}
        local lv = v.lv
        t.lvT = self:ParseRange(lv)
        local reward = v.reward
        t.rewardT = LxDataHelper.ParseItem(reward)
        self._seasonBoxRefT[k] = t
    end

    self._rankArenaPeakAwardRef = {}
    for k, v in pairs(GameTable.ArenaPeakWarAwardRef) do
        local t = {}
        t.rankT = {
            left = v.rankMax,
            right = v.rankMin,
        }

        local titleReward = v.titleReward

        local tRewardList = LxDataHelper.ParseItem(titleReward) or {}

        local reward = v.reward

        local nRewardList = LxDataHelper.ParseItem(reward) or {}

        for p, q in ipairs(nRewardList) do
            table.insert(tRewardList, q)
        end

        t.rewardT = tRewardList
        self._rankArenaPeakAwardRef[k] = t
    end

    local alterAward = GameTable.ArenaPeakWarRef["alterAward1"]
    self._alterAward1 = LxDataHelper.ParseItem(alterAward)
    alterAward = GameTable.ArenaPeakWarRef["alterAward2"]
    self._alterAward2 = LxDataHelper.ParseItem(alterAward)

    local cfg = GameTable.RookieArenaParRef["SkipTime"]
    local strs = string.split(cfg, ";")
    local list = {}
    for k, v in ipairs(strs) do
        local paras = LxDataHelper.ParseNumber_Sign(v, "=")
        if #paras >= 2 then
            local data = {
                level = paras[1],
                times = paras[2],
            }
            table.insert(list, data)
        end
    end

    self._skipLimitList = list
end

function ModelArena:ParseRange(str)
    local s, e, cap1, cap2 = string.find(str, "{(%d+),(%d+)}")
    if not cap1 or not cap2 then
        printInfoN("ModelArena:ParseRange, wrong cfg " .. str)
    end
    local t = {
        left = tonumber(cap1),
        right = tonumber(cap2),
    }
    return t
end

