function ModelArena:OnPinnaclePaceStateResp(pb)
    local oldState = self._peakState
    --local oldStage = self._peakStage
    local oldRound = self._peakRound
    self._peakState = pb.state                  --（1.未开启，2.已开启 3.已结束）
    self._peakCombatState = pb.combatState
    self._peakStartTime = pb.startTime
    self._peakNextStageTime = pb.nextStageTime
    self._guessCoin = pb.guessCoin
    self._peakStage = pb.stage
    self._peakRound = pb.round
    self._peakRank = pb.rank
    self._peakMaxRank = pb.rankMax
    self._championName = pb.championName
    -- self._guessBackCount = pb.guessBackCount
    -- self._guessBackCoin = pb.guessBackCoin
    self._matchGroupId = pb.matchGroupId

    -- 【G公共支持】删除跨服天梯和跨服周冠玩法
    -- local isShowForeignGuess = gModelCrossServer:CheckUseGuessForeign()
    local noticeId = ModelGeneral.NOTICE_ARENAPEAK
    -- if isShowForeignGuess and self._peakCombatState == ModelArena.PEAK_BATTLE_STATE_BETTING then
    --     noticeId = ModelGeneral.NOTICE_ARENAPEAK_FOREIGN
    --     gModelGeneral:SetDeleteNoticeListItem(ModelGeneral.NOTICE_ARENAPEAK)
    -- else
    gModelGeneral:SetDeleteNoticeListItem(ModelGeneral.NOTICE_ARENAPEAK_FOREIGN)
    -- end
    gModelGeneral:GetSetNoticeListItem(noticeId, self._peakStartTime / 1000, self._peakState)

    --local arenaKey = 13000000
    local arenaPeakKey = 13200000
    --local isArenaOpen = gModelFunctionOpen:CheckIsOpened(arenaKey)
    local isArenaOpen = true
    local isArenaPeakOpen = gModelFunctionOpen:CheckIsOpened(arenaPeakKey)

    if not isArenaPeakOpen or not isArenaOpen then
        return
    end

    if oldState then
        ---已登录
        if oldState ~= ModelArena.PEAK_STATE_STARTED and self._peakState == ModelArena.PEAK_STATE_STARTED then
            self._watchedBattle = nil
            self._groupInfoMap = {}
        end

        ---新加每轮开始弹出弹窗
        --if self._peakStage == ModelArena.PEAK_BATTLE_STATE_UNSTART then
        if oldRound ~= self._peakRound then
            self._groupInfoMap = {}
            self:OpenPopWnd()
        end
        --end

    else
        ---未登录
        if self._peakState == ModelArena.PEAK_STATE_STARTED then
            self:OpenPopWnd()
        end
    end

    FireEvent(EventNames.ON_PEAK_STATE_CHANGE)

end

