function ModelArena:IsInStage()
    --是否入围
    local stage = self:GetPeakStage()
    local personPerStage = {
        [1] = 9999,
        [2] = 64,
        [3] = 32,
        [4] = 16,
        [5] = 8,
        [6] = 4,
        [7] = 2,
    }
    local person = personPerStage[stage]
    if not person then
        return false, stage
    end
    local rank = self:GetPeakRank() or 0
    if rank > 0 and rank <= person then
        return true
    end
    return false, stage
end

