function ModelArena:GetPeakOpenTime(isGuess)
    local leftTime = 0
    if self:GetPeakStartTime() > 1 then
        leftTime = self:GetPeakStartTime() - GetTimestamp()
    else
        local firstOpenDay = gModelArena:GetArenaPeakRef("serverOpenDays")
        local startTime = gModelArena:GetArenaPeakRef("champStartTime")
        local startDay = gModelArena:GetArenaPeakRef("openDays") - 1
        local readyTime = isGuess and gModelArena:GetArenaPeakRef("readyTime") or 0
        local serverDay = gLGameLogin:GetServerOpenDay()
        local timeInfo = string.split(startTime, ":")
        local statTime = (timeInfo[1] * 60 * 60) + (timeInfo[2] * 60) + timeInfo[3] + readyTime
        local nowTime = GetTimestamp()
        local nowH = tonumber(os.date("%H", nowTime))
        local nowM = tonumber(os.date("%M", nowTime))
        local nowS = tonumber(os.date("%S", nowTime))
        local nowTick = (nowH * 60 * 60) + (nowM * 60) + nowS
        local nowWeek = tonumber(os.date("%w", nowTime))
        if startDay < nowWeek or statTime - nowTick < 0 then
            startDay = startDay + 7
        end
        if serverDay < firstOpenDay then
            startDay = startDay + firstOpenDay - serverDay
        end
        local day = startDay - nowWeek
        leftTime = day * 86400 + (statTime - nowTick)
    end

    return math.ceil(leftTime)
end

