function ModelArena:GetCombatIsEnd(round)
    local state = self:GetPeakState()
    if state == ModelArena.PEAK_STATE_BEFORE then
        return true
    elseif state == ModelArena.PEAK_STATE_STARTED then
        local curRound = self:GetPeakRound()
        if round < curRound then
            return true
        end
    elseif state == ModelArena.PEAK_STATE_END then
        return true
    end
    return false
end

