function ModelArena:OpenPopWnd()
    local wnd = GF.FindFirstWndByName("UIringPk")
    local foreignWnd = GF.FindFirstWndByName("UIPkGuessForeign")
    if wnd and not foreignWnd then
        return
    end

    local isIn = self:IsInStage()
    local pageIndex = 1
    local wndId = 50602
    local rewards = self._alterAward1
    if not isIn then
        wndId = 50603
        pageIndex = 2
        rewards = self._alterAward2
    end
    for _, v in ipairs(rewards) do
        v.hideNum = true
    end

    local confirmFunc = function()
        FireEvent(EventNames.ONLY_CHANGE_MAIN_BTN_ON, { index = LMainBtnIndexConst.OUTSKIRTS })

        GF.OpenWndBottom("UIOutts", { childIndex = 2 })
        GF.OpenWndBottom("UIringPk", { page = pageIndex })
    end

    local stageStr = self._stageStrList[self._peakStage] or self._stageStrList[1]

    gModelGeneral:RemovePopWndPara(50602)
    gModelGeneral:RemovePopWndPara(50603)

    local para = { refId = wndId, func = confirmFunc, itemList = rewards, para = { stageStr } }
    if foreignWnd then
        --在海外竞猜界面时，可以打开
        gModelGeneral:OpenUIOrdinTips(para)
    else
        gModelGeneral:InsertPopWndPara(para)
        gModelGeneral:OpenPopWnd()
    end
end

