function ModelArena:CanSkipArena(showTip)
    if not self._skipLimitList then
        return false
    end
    local level = gModelPlayer:GetPlayerLv()
    local times = 0
    for k, v in ipairs(self._skipLimitList) do
        local limitLv = v.level
        if level >= limitLv then
            times = v.times
        else
            break
        end
    end

    local seasonCnt = self:GetSeasonChallengeTimes()

    local lack = times - seasonCnt
    local canSkip = lack <= 0
    if not canSkip and showTip then
        GF.ShowMessage(string.replace(ccClientText(10344), lack))
    end
    return canSkip
end

