function ModelArena:FormatScheduleBtnsData(infos, guessId, isGroup)
    -- local cnt = 3
    -- if isGroup then
    cnt = 7
    -- end

    local curCombatState = self:GetPeakCombatState()

    local t = {}
    for i = 1, cnt do
        local result = infos[i]
        local data = {}
        if result then

            local isEnd = self:GetCombatIsEnd(result.round)
            if isEnd then
                data.isAfter = true
                data.reportId = result.reportId
                data.leftName = result.attack.name
                data.rightName = result.defense.name
                local arenaCombatInfo = StructCombatResultInfo:New()
                arenaCombatInfo:CreateByPb(result)
                data.arenaCombatInfo = arenaCombatInfo
            else
                if curCombatState < ModelArena.PEAK_BATTLE_STATE_BETTING then
                    data.isBefore = true
                elseif curCombatState == ModelArena.PEAK_BATTLE_STATE_BETTING then
                    if guessId == result.reportId then
                        data.isBetting = true
                    else
                        data.isBefore = true
                    end
                elseif curCombatState == ModelArena.PEAK_BATTLE_STATE_FIGHTING then
                    data.isAfter = true
                    data.reportId = result.reportId
                    data.leftName = result.attack.name
                    data.rightName = result.defense.name
                    local arenaCombatInfo = StructCombatResultInfo:New()
                    arenaCombatInfo:CreateByPb(result)
                    data.arenaCombatInfo = arenaCombatInfo
                end
            end
            data.round = result.round
        else
            data.isBefore = true
        end

        table.insert(t, data)
    end
    return t
end

function ModelArena:FormatScheduleLineData(infos, isGroup)
    local linesData = {}
    local cnt = isGroup and 7 or 7
    local result = nil

    local winnerId = {}
    for i = 1, cnt do
        local data = infos[i]
        if data then
            local isEnd = self:GetCombatIsEnd(data.round)
            result = isEnd and data.winner or 0

            if result == 1 then
                winnerId[i] = data.attack.playerId
            elseif result == 2 then
                winnerId[i] = data.defense.playerId
            end
            if isGroup then
                if i == 5 then
                    if winnerId[1] ~= data.attack.playerId then
                        result = self:ConvertResult(result)
                    end
                elseif i == 6 then
                    if winnerId[3] ~= data.attack.playerId then
                        result = self:ConvertResult(result)
                    end
                elseif i == 7 then
                    if winnerId[5] ~= data.attack.playerId then
                        result = self:ConvertResult(result)
                    end
                end
                -- else
                --     if i== 3 then
                --         if winnerId[1]~= data.attack.playerId then
                --             result = self:ConvertResult(result)
                --         end
                --     end
            end

        else
            result = 0
        end
        linesData[i] = result
    end
    return linesData
end

function ModelArena:ConvertResult(result)
    if result == 1 then
        return 2
    elseif result == 2 then
        return 1
    end
    return result
end

function ModelArena:FormatSchedulePlayData(infos, isGroup)
    local players = {}
    local cnt = isGroup and 4 or 2
    cnt = 4
    for i = 1, cnt do
        local data = infos[i]
        if data then
            table.insert(players, data.attack)
            table.insert(players, data.defense)
        end
    end
    return players
end

function ModelArena:FormatScheduleWinnerData(resultList, isGroup)
    local round = 12 --决赛轮次
    local index = 7
    if isGroup then
        index = 7
        round = 9 --8强轮次
    end

    local isEnd = self:GetCombatIsEnd(round)
    if not isEnd then
        return nil
    end
    local winnerData = {}

    local result = resultList[index]
    if result then
        local winner = result.winner
        if winner == 1 then
            winnerData.player = result.attack
        elseif winner == 2 then
            winnerData.player = result.defense
        else
            return nil
        end
    else
        return nil
    end

    return winnerData
end

function ModelArena:FormatSchedulePlayerList(players, isGroup)
    local playerList = {}
    local cnt = 4
    if isGroup then
        cnt = 8
    end
    cnt = 8
    for i = 1, cnt do
        local playerdata = players[i]
        local data = {}
        if playerdata then
            data.head = playerdata.head
            data.name = playerdata.name
            data.grade = playerdata.grade
            data.playerId = playerdata.playerId
            data.headFrame = playerdata.headFrame
        else
            data.isEmpty = true
        end
        table.insert(playerList, data)
    end
    return playerList
end

