function ModelArena:GoToChallenge(data, wndName)
    local canFreeChallenge = self:CanFreeChallenge()
    if not canFreeChallenge then
        local ticketId = self:GetArenaPara("TciketId")
        local own = tonumber(gModelItem:GetNumByRefId(ticketId))
        local req = self:GetArenaPara("TicketNum")
        if own < req then
            gModelGeneral:OpenGetWayWnd({ itemId = ticketId, srcWnd = wndName })
            return
        end
    end
    local prepareFunc = function()
        local combatExtraData = { playerId = data.playerId, otherName = data.name, otherPlayerHead = data.head, otherLevel = data.grade }
        gLFightManager:PrepareGoToBattle(LCombatTypeConst.COMBAT_ARENA_ATTACK, combatExtraData)
    end

    local skipFunc = function()
        local combatData = {
            combatType = LCombatTypeConst.COMBAT_ARENA_ATTACK,
            targetId = data.playerId,
            skipBattle = true,
        }

        self:SetChallengeDataDirty(true)

        gModelBattle:OnCombatReq(combatData)
    end

    local needCheck = false
    local battleNode = self:GetArenaPara("heorCombatTips")
    local isPass = gModelInstance:IsBattleNodePass(battleNode)
    if isPass then
        local heroOnCnt = gModelFormation:GetFormationHerosNum(LCombatTypeConst.COMBAT_ARENA_ATTACK)
        if heroOnCnt < 5 then
            needCheck = true
        end
    end

    local isSkipPrepare = self:IsSkipPrepare()
    local isSkip = self:GetIsSkipChecked()
    if isSkip and isSkipPrepare then

        if needCheck then
            local para = {
                refId = 50604,
                leftFunc = prepareFunc,
                func = skipFunc,
            }

            gModelGeneral:OpenUIOrdinTips(para)
            return
        end

        skipFunc()

        return
    end

    local battleFunc = function()
        local combatData = {
            combatType = LCombatTypeConst.COMBAT_ARENA_ATTACK,
            targetId = data.playerId,
            skipBattle = false,
            meName = gModelPlayer:GetPlayerName(),
            otherName = data.name,
            otherPlayerHead = data.head,
            otherLevel = data.grade
        }

        gModelBattle:StartAfterSetFormation(combatData)
    end

    if isSkipPrepare then

        local battleNode = self:GetArenaPara("heorCombatTips")
        local isPass = gModelInstance:IsBattleNodePass(battleNode)
        if isPass then
            local heroOnCnt = gModelFormation:GetFormationHerosNum(LCombatTypeConst.COMBAT_ARENA_ATTACK)
            if heroOnCnt < 5 then
                local para = {
                    refId = 50604,
                    leftFunc = prepareFunc,
                    func = battleFunc,
                }

                gModelGeneral:OpenUIOrdinTips(para)
                return
            end
        end

        battleFunc()
        return
    end

    prepareFunc()
end

function ModelArena:CanChangeFormation()
    local state = self:GetPeakState()
    local combatState = self:GetPeakCombatState()

    -- 【G公共支持】删除跨服天梯和跨服周冠玩法
    -- if gModelCrossServer:CheckUseGuessForeign() then
    --     if combatState== ModelArena.PEAK_BATTLE_STATE_FIGHTING then
    --         return false
    --     end
    -- else
    if state == ModelArena.PEAK_STATE_STARTED
            and (combatState == ModelArena.PEAK_BATTLE_STATE_BETTING
            or combatState == ModelArena.PEAK_BATTLE_STATE_FIGHTING) then
        return false

    end
    -- end

    return true
end

